noncompliant:
// Noncompliant - unsealed class implementing IEquatable
public class MyClass : IEquatable<MyClass>
{
    public bool Equals(MyClass other)
    {
        // ...
    }
}

compliant:
// Option 1: Seal the class
public sealed class MyClass : IEquatable<MyClass>
{
    public bool Equals(MyClass other)
    {
        // ...
    }
}

// Option 2: Make Equals virtual
public class MyClass : IEquatable<MyClass>
{
    public virtual bool Equals(MyClass other)
    {
        // ...
    }
}
